INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05550', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '核心概念是解決問題，強調組織中的每個人都應致力於找出問題和解決問題，以使組織能夠不斷的嘗試 錯誤、改善問題，以提高自我能力。此描述符合下列何種管理思維？', '["人群關係學派", "知識管理", "組織環境理論", "學習型組織"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05551', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '雙因子理論（motivation-hygiene theory）是由心理學家赫茨伯格（Frederick Herzberg）所提出，主張管理 者在激勵員工時，需要區分保健因子與激勵因子，以能達激勵效果。下列對於此理論的敘述，何者正確？', '["針對保健因子予以激勵只能防止員工的不滿足，無法使員工感到滿足", "保健因子包括成就感、賞識、責任與成長機會等高層次的需求", "激勵因子包括薪資、工作條件、公司政策與同事關係等較低層次的需求", "此理論對管理者的啟示是應著重高層次需求的激勵，忽略低層次需求，以能驅使員工達到更高成就境界"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05552', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '運用所蒐集的資料來回答「方案依設計所執行的程度為何？」、「員工所執行的措施是否符合方案所規 劃的？」、「方案是否涵蓋適當的受益者？」等問題，屬於下列何種方案評估活動？', '["總結評估", "結果評估", "過程評估", "影響評估"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05553', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「是一種財務計畫，也是行動計畫，是即將實現的服務與發展藍圖，有引導實現社會服務組織使命的功 能」，此是描述下列何種財務管理活動？', '["會計工作", "預算", "財務分析", "投資管理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05554', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在一個社會服務機構中，主管正對社工員的表現進行績效考核。考核甲社工員時，主管記起甲曾在幾個 月前工作遲到數次，因此將其績效評為丙等，儘管甲社工員其他工作表現符合規定。此情境說明了何種 績效考核潛在問題？', '["初始效應", "尖角效應", "月暈效應", "盲點效應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05555', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '為能因應內、外部環境的變化，社會服務機構需有策略性規劃（strategic management）的能力，以釐清組 織運作方向，增進面臨挑戰與控制的能力。下列對於進行策略性規劃的描述，何者正確？', '["首要步驟為「確認當前的使命與目標」", "SWOT分析為進行「檢視外部環境」此步驟時常用的技術", "「再評估組織的使命與目標」此一步驟是針對組織進行綜合性的考量，又可稱為PEST分析", "組織經過策略性規劃後將可朝「穩定策略」發展，意指可增加營運範圍"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05556', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '當前對於機構員工績效考核的方法推陳出新，在這些考核方法中，強調從各種角度來評估員工的績效表 現，藉由多元績效評估回饋機制以強化考核的客觀性與公平性，是下列何種考核方法？', '["360度考評法", "行為定錨量表法", "平衡計分卡", "特質取向法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05557', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「督導」對於社會工作而言具有重要功能與意義，下列對於督導情境描述的功能歸類，何者錯誤？', '["督導過程中強調受督導者需發展專業工作的認知與技能，此為督導的「教育性」功能", "提供規律且定期的督導，使受督導者對其工作內容與過程有反省的機會，此為督導的「行政性」功能", "在督導過程中對受督導者提供心理與人際關係支持，此為督導的「支持性」功能", "藉由督導來協調社工員與機構組織間的衝突，此為督導的「調解性」功能"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05558', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在社會服務機構裡，人力資源的培訓包含兩種：員工訓練及員工發展，兩種活動對於機構與員工而言均 有重要功能與目的。下列對於兩種活動內涵的描述，何者正確？', '["員工訓練強調具有未來取向，以幫助員工發揮潛能", "員工發展強調現實取向，重點是學習可以現學現賣的知識與技巧", "員工訓練是為改善員工工作表現而設計，以使員工的工作更具效率與效能", "員工發展為能增加員工在工作上的自信，因此實施的主題均會與員工目前工作內容直接相關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05559', 'social-worker', 'social-worker-moex-106-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「須讓員工清楚明白組織的目標，並運用自身的影響力來激發、激勵員工致力組織的效能和成就，以達 到組織的目標。」請問此段描述符合下列那種管理活動的定義？', '["任用", "控制", "組織", "領導"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "15e37dd6688d", "answer_pdf_sha1": "e38b093537b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
